				import sailpoint.object.Custom;
        import sailpoint.tools.Util;
        import sailpoint.object.Identity;
        import sailpoint.object.Application;
        import sailpoint.object.Link;
        import sailpoint.api.IdentityService;
        import org.apache.commons.logging.LogFactory;
        import org.apache.commons.logging.Log;
        import sailpoint.tools.GeneralException;
        

        Log logger = LogFactory.getLog("Workflow-Ascension-Lifecycle-OIM-Data");

        Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-OIM-Data-AMITA");
        Custom ascensionCustom = context.getObjectByName(Custom.class,"Ascension-Custom-OIM-Data-Ascension");
        
        String amitaDomainName = "";
        String setIdLocationFromCustom = "";
        String setIdLocationOnLink = "";
        String domainOnUser= "";
		String employeeId= "";
        boolean hasPeopleSoftAccount = false;
        
        try{
          if(Util.isNotNullOrEmpty(identityName)){
            Identity idObj = context.getObjectByName(Identity.class, identityName);
            if(idObj != null && custom != null){
              amitaDomainName = custom.get("Amita Domain Name");
              setIdLocationFromCustom = custom.get("Set Location ID");
              String peopleSoftAppName = custom.get("Peoplesoft App Name");

              domainOnUser = idObj.getAttribute("domain");
			  employeeId = idObj.getStringAttribute("employeeId");

              if(Util.isNotNullOrEmpty(peopleSoftAppName)){
                Application application = context.getObjectByName(Application.class, peopleSoftAppName);
                if(idObj != null && application != null){
                  IdentityService identityService = new IdentityService(context);
                  List links = Util.filterNulls(identityService.getLinks(idObj, application));
                  if(!Util.isEmpty(links)){
                    for (Object object : links) {
                      Link link = (Link) object;
                      if(link!=null){
                        setIdLocationOnLink = (String) link.getAttribute("SETID_LOCATION");
                        hasPeopleSoftAccount = true;
                      }
                    }
                  }
                  //comment decache //context.decache(application);
                  //comment decache //context.decache(idObj);
                }
              }
            }
          }
        }catch(GeneralException e){
          logger.error("GeneralException in Step Process Identity Details: "+e.getMessage());
        }
        
        logger.debug("Starting  Process Identity Details Step");
        
        if(custom != null && Util.isNotNullOrEmpty(amitaDomainName) 
        && Util.isNotNullOrEmpty(setIdLocationFromCustom) && Util.isNotNullOrEmpty(setIdLocationOnLink) &&
        (Util.nullSafeCaseInsensitiveEq(domainOnUser,amitaDomainName) || Util.nullSafeCaseInsensitiveEq(setIdLocationOnLink,setIdLocationFromCustom)) && hasPeopleSoftAccount){
         //Flow for AMITA
         try{
           logger.debug("In workflow Process Identity Details Step - AMITA Users");
           Object obj = custom.get("User ID and Email Changes");
            if(Util.isNotNullOrEmpty(employeeId)){
				if(obj != null && obj instanceof List){
					if(!obj.contains(employeeId)){
						obj.add(employeeId);
						custom.put("User ID and Email Changes", obj);
					}              
				}else{
				  List idList = new ArrayList();
				  idList.add(employeeId);
				  custom.put("User ID and Email Changes", idList);
				}
				context.saveObject(custom);
				context.commitTransaction();
				//comment decache //context.decache(custom);
			}
          }catch(GeneralException e){
        		logger.error("GeneralException in Step Process Identity Details: "+e.getMessage());
        	}
        }else if(ascensionCustom != null && Util.isNotNullOrEmpty(amitaDomainName) 
        && Util.isNotNullOrEmpty(setIdLocationFromCustom) && Util.isNotNullOrEmpty(setIdLocationOnLink) &&
        (!Util.nullSafeCaseInsensitiveEq(domainOnUser,amitaDomainName) || !Util.nullSafeCaseInsensitiveEq(setIdLocationOnLink,setIdLocationFromCustom)) && hasPeopleSoftAccount){
         //flow for Ascension
        	try{
           	logger.debug("In workflow Process Identity Details Step - Ascension Users");
            Object obj = ascensionCustom.get("Identities Changed");
            if(Util.isNotNullOrEmpty(employeeId)){
				if(obj != null && obj instanceof List){
					if(!obj.contains(employeeId)){
						obj.add(employeeId);
						ascensionCustom.put("Identities Changed", obj);
					}
				}else{
				  List idList = new ArrayList();
				  idList.add(employeeId);
				  ascensionCustom.put("Identities Changed", idList);
				}
				context.saveObject(ascensionCustom);
				context.commitTransaction();
				//comment decache //context.decache(ascensionCustom);
			}
         }catch(GeneralException e){
          logger.error("GeneralException in Step Process Identity Details: "+e.getMessage());
         }
        }
        logger.debug(" End Process Identity Details Step  ");
